INSERT INTO `news_slides` (`id`, `title`, `language`, `description`, `image_url`, `link_url`, `is_active`, `display_order`, `created_at`, `updated_at`) VALUES
(1, 'Mémoire Nationale : Nouvelle Loi', 'fr', 'ALGER - Plusieurs partis politiques ont salué l''adoption, à l''unanimité, de la proposition de loi criminalisant la colonisation française en Algérie, la qualifiant d''étape historique reflétant l''attachement de l''Etat algérien à la mémoire nationale et un hommage collectif aux sacrifices des martyrs.', 'https://www.aps.dz/fr/_next/image?url=%2Ffr%2Fapi%2Fimage%2Farticle%2F0afcc8ee7a4ce1bd80a6de98cf2d6353.webp&w=1080&q=75', 'https://www.aps.dz/fr/algerie/actualite-nationale/mjlog36b-loi-criminalisant-la-colonisation-francaise-en-algerie-une-etape-historique-refletant-l-attachement-de-l-etat-a-la-memoire-nationale', 1, 0, '2026-01-20 23:14:32', '2026-01-20 23:14:32'),
(2, 'Loi de Finances 2026', 'fr', 'La Loi de finances 2026 consacre le plus gros budget jamais adopté par l’Algérie. Les recettes sont estimées à 8.009.025.301.630 dinars (plus de 61 milliards de dollars), tandis que les dépenses atteignent 17.636.662.280.000 dinars, soit plus de 135 milliards de dollars.', 'https://www.algerie360.com/wp-content/smush-webp/2026/01/Entree-en-vigueur-de-la-loi-des-Finance-2026.jpeg.webp', 'https://www.algerie360.com/la-loi-de-finances-2026-publiee-au-jo-importation-de-vehicules-taxes-croissance-les-points-cles/', 1, 1, '2026-01-20 23:15:47', '2026-01-20 23:15:47'),
(3, 'L''Intelligence Artificielle au service du Droit Algérien', 'fr', 'dz-legal-ai analyse les textes juridiques algériens officiels (Journal Officiel, Codes) et utilise des modèles de langage avancés pour comprendre votre question, rechercher les articles pertinents, et générer une réponse précise en langage clair.', 'https://dz-legal-ai.com/logo_w.png', 'https://dz-legal-ai.com/logo_w.png', 0, 2, '2026-01-20 23:20:02', '2026-02-06 10:29:33'),
(4, 'نص قانون تجريم الاستعمار الفرنسي في الجزائر خطوة مفصلية في مسار تثبيت الذاكرة الوطنية', 'ar', 'الجزائر - أكد وزير المجاهدين وذوي الحقوق، السيد عبد المالك تاشريفت، اليوم الاثنين بالجزائر العاصمة، أن نص قانون تجريم الاستعمار الفرنسي في الجزائر هو خطوة مفصلية في مسار تثبيت الذاكرة الوطنية ضمن منظومة قانونية تحصن التاريخ وترسخ الوعي الجماعي للأمة.', 'https://www.aps.dz/_next/image?url=%2Fapi%2Fimage%2Farticle%2Fda03243e85ba1f9a9269570a3c1d50ea.webp&w=1080&q=75', 'https://www.aps.dz/algerie/actualite-nationale/mklm4it2-نص-قانون-تجريم-الاستعمار-الفرنسي-في-الجزائر-خطوة-مفصلية-في-مسار-تثبيت-الذاكرة-الوطنية', 1, 0, '2026-01-20 23:35:02', '2026-01-20 23:35:02'),
(5, 'الذكاء الاصطناعي في خدمة القانون الجزائري', 'ar', 'يقوم ذكاؤنا الاصطناعي بتحليل النصوص القانونية الجزائرية الرسمية (الجريدة الرسمية، القوانين) ويستخدم نماذج لغوية متقدمة لفهم سؤالك، والبحث عن المواد ذات الصلة، وتوليد إجابة دقيقة بلغة واضحة.', 'https://dz-legal-ai.com/logo_w.png', 'https://dz-legal-ai.com', 0, 1, '2026-01-20 23:36:48', '2026-02-06 10:29:51'),
(6, 'قانون المالية 2026 يصدر بالجريدة الرسمية', 'ar', 'الجزائر- صدر في العدد 88 من الجريدة الرسمية قانون المالية لسنة 2026, والذي وقع عليه رئيس الجمهورية, السيد عبد المجيد تبون, في 14 ديسمبر الجاري.\n\nونص القانون, الذي صادق عليه مجلس الأمة في 4 ديسمبر الجاري, والمجلس الشعبي الوطني في 18 نوفمبر الفارط, على عدة تدابير تشريعية تهدف بشكل رئيسي إلى ترقية الاستثمار, وتعزيز الاقتصاد الوطني مع تبسيط الاجراءات الجبائية, وكذا دعم القدرة الشرائية مع تحسين الإطار المعيشي للمواطنين.\n\nويتوقع القانون أن يبلغ معدل النمو الاقتصادي 1ر4 بالمائة سنة 2026, و4ر4 بالمائة سنة 2027, و5ر4 بالمائة سنة 2028, مدفوعا بالأداء المنتظر للقطاعات خارج المحروقات.', 'https://www.aps.dz/_next/image?url=%2Fapi%2Fimage%2Farticle%2Fac48f7da50958b3e14146c56addfd77b.webp&w=1080&q=75', 'https://www.aps.dz/economie/banque-et-finances/mju6wej9-قانون-المالية-2026-يصدر-بالجريدة-الرسمية', 1, 2, '2026-01-20 23:41:39', '2026-01-20 23:41:39'),
(7, 'Le gouvernement durcit sa législation sur la déchéance de nationalité', 'fr', 'L’Assemblée populaire nationale (APN) examine ce mercredi 17 décembre, en présence du ministre de la Justice Lotfi Boudjemaâ, une proposition de loi modifiant le code de la nationalité algérienne de 1970.', 'https://www.tsa-algerie.com/wp-content/uploads/2025/12/passeport-Par-hamzeh-min.jpg.webp', 'https://www.tsa-algerie.com/decheance-de-la-nationalite-algerienne-ce-que-prevoit-le-projet-de-loi/', 1, 3, '2026-01-21 10:10:08', '2026-01-21 10:10:08'),
(8, 'توسيع إجراءات التجريد من الجنسية وفق شروط محدّدة', 'ar', 'أكد وزير العدل حافظ الأختام، لطفي بوجمعة، أمس، نصّ قانون المتعلق بالجنسية، جاء من أجل حماية سيادة الوطن واستقراره ووحدته الترابية، من خلال توسيع إجراءات التجريد من الجنسية حتى الأصلية منها وفق شروط محددة بدقة، مبرزا بأنه لا يتم التجريد من الجنسية الأصلية إلا إذا كان المعني يحوز جنسية أخرى.', 'https://www.el-massa.com/dz/media/k2/items/cache/14da86130a4860c3047417828ea0d82e_XL.jpg', 'https://www.el-massa.com/dz/%D8%A7%D9%84%D8%AD%D8%AF%D8%AB/%D8%AA%D9%88%D8%B3%D9%8A%D8%B9-%D8%A5%D8%AC%D8%B1%D8%A7%D8%A1%D8%A7%D8%AA-%D8%A7%D9%84%D8%AA%D8%AC%D8%B1%D9%8A%D8%AF-%D9%85%D9%86-%D8%A7%D9%84%D8%AC%D9%86%D8%B3%D9%8A%D8%A9-%D9%88%D9%81%D9%82-%D8%B4%D8%B1%D9%88%D8%B7-%D9%85%D8%AD%D8%AF%D9%91%D8%AF%D8%A9', 1, 3, '2026-01-21 10:11:34', '2026-01-21 10:11:34'),
(9, 'Nouvelles mesures pour permettre aux partis et aux associations de se conformer à la loi sur le traitement des données à caractère personnel', 'fr', '\'Autorité nationale de protection des données à caractère personnel (ANPDP) a annoncé, lundi dans un communiqué, de nouvelles mesures numériques permettant aux partis politiques et aux associations de se conformer à la loi relative à la protection des personnes physiques dans le traitement des données à caractère personnel.', 'https://www.aps.dz/fr/_next/image?url=%2Ffr%2Fapi%2Fimage%2Farticle%2F94544c493dd7036dae3dc6ce10610c92.webp&w=1080&q=75', 'https://www.aps.dz/fr/algerie/actualite-nationale/mkli4s1u-nouvelles-mesures-pour-permettre-aux-partis-et-aux-associations-de-se-conformer-a-la-loi-sur-le-traitement-des-donnees-a-caractere-personnel', 1, 4, '2026-01-21 10:18:41', '2026-01-21 10:18:41'),
(10, 'Le président de la République salue hautement le niveau très avancé de la numérisation atteint dans l''ensemble des secteurs', 'fr', 'ALGER - Le président de la République, M. Abdelmadjid Tebboune, a hautement salué, lors de la réunion du Conseil des ministres qu''il a présidée dimanche, le niveau très avancé atteint par l''Algérie dans la numérisation des informations et des données dans l''ensemble des secteurs, indique un communiqué du Conseil des ministres.', 'https://www.aps.dz/fr/_next/image?url=%2Ffr%2Fapi%2Fimage%2Farticle%2F28db9f8aa38917410e3986112b13dbfc.jpg&w=1080&q=75', 'https://www.aps.dz/fr/presidence-news/mka8hoi1-le-president-de-la-republique-salue-hautement-le-niveau-tres-avance-de-la-numerisation-atteint-dans-l-ensemble-des-secteurs', 1, 5, '2026-02-06 09:43:40', '2026-02-06 09:43:40'),
(11, 'رئيس الجمهورية يثمن عاليا مستوى الرقمنة الجد متقدم في كل القطاعات', 'ar', 'الجزائر - ثمن رئيس الجمهورية, السيد عبد المجيد تبون, لدى ترؤسه اليوم الأحد اجتماعا لمجلس الوزراء, عاليا وصول الجزائر إلى مستوى جد متقدم في رقمنة المعلومات والبيانات في كل القطاعات, حسب ما أفاد به بيان لمجلس الوزراء.', 'https://www.aps.dz/_next/image?url=%2Fapi%2Fimage%2Farticle%2Fe4378f898f8e9ac838a9c5d663fcce96.jpg&w=1080&q=75', 'https://www.aps.dz/presidence-news/mka5e2ji-', 1, 5, '2026-02-06 09:45:30', '2026-02-06 09:45:30'),
(12, 'Exportations hors hydrocarbures', 'fr', 'L’Algérie enregistre des progrès en matière d’investissements, d’exportations hors hydrocarbures, de numérisation… : c’est le FMI qui le dit !', 'https://www.aps.dz/_next/image?url=%2Fapi%2Fimage%2Farticle%2F6d2e1df09df2e6277be519b3186ac011.jpeg&w=1080&q=75', 'https://www.elmoudjahid.dz/fr/actualite/l-algerie-enregistre-des-progres-en-matiere-d-investissements-d-exportations-hors-hydrocarbures-de-numerisation-c-est-le-fmi-qui-le-dit-247513', 1, 6, '2026-02-06 09:47:55', '2026-02-06 09:47:55'),
(13, 'الصادرات خارج المحروقات', 'ar', 'الجزائر - نوهت المديرة العامة لصندوق النقد الدولي، كريستالينا غورغييفا، بالتقدم الذي أحرزته الجزائر في السنوات الأخيرة في مجال ترقية الاستثمار والرقمنة وتعزيز الصادرات خارج المحروقات، مبرزة بشكل خاص الأسس الاقتصادية القوية للجزائر.', 'https://www.aps.dz/_next/image?url=%2Fapi%2Fimage%2Farticle%2F6d2e1df09df2e6277be519b3186ac011.jpeg&w=1080&q=75', 'https://www.aps.dz/economie/banque-et-finances/ml86nbd4-%D8%A7%D9%84%D8%AC%D8%B2%D8%A7%D9%8A%D9%94%D8%B1-%D8%A7%D9%94%D8%AD%D8%B1%D8%B2%D8%AA-%D8%AA%D9%82%D8%AF%D9%85%D8%A7-%D9%81%D9%8A-%D9%85%D8%AC%D8%A7%D9%84-%D8%AA%D8%B1%D9%82%D9%8A%D8%A9-%D8%A7%D9%84%D8%A7%D8%B3%D8%AA%D8%AB%D9%85%D8%A7%D8%B1-%D9%88%D8%AA%D9%86%D9%88%D9%8A%D8%B9-%D8%A7%D9%84%D8%A7%D9%82%D8%AA%D8%B5%D8%A7%D8%AF', 1, 6, '2026-02-06 09:48:59', '2026-02-06 09:48:59'),
(14, 'Transformation numérique globale', 'fr', 'l''Algérie s''est engagée dans un processus de transformation numérique globale, en application des instructions fermes du président de la République, M. Abdelmadjid Tebboune, quant à l''impératif de parachever la généralisation de la numérisation selon une vision stratégique reflétant la volonté de l''Etat de consacrer la transparence dans la gestion et d''éradiquer les formes de corruption et de bureaucratie.', 'https://news.radioalgerie.dz/sites/default/data/styles/d09_traditional/public/2025-09/plateforme_numerique.webp?h=032abc86&itok=VwkW4LbB', 'https://news.radioalgerie.dz/fr/node/77043', 1, 7, '2026-02-06 09:53:58', '2026-02-06 09:53:58'),
(15, 'تحول رقمي شامل', 'ar', 'الجزائر - عملت الجزائر, خلال سنة 2025, على التوجه بخطى ثابتة نحو تحقيق تحول رقمي شامل, تجسيدا للتعليمات الصارمة لرئيس الجمهورية, السيد عبد المجيد تبون , بضرورة الانتهاء من عملية تعميم الرقمنة ضمن رؤية \nاستراتيجية شاملة تعكس إرادة الدولة في تكريس الشفافية في التسيير والقضاء على أشكال الفساد والبيروقراطية.', 'https://news.radioalgerie.dz/sites/default/data/styles/d09_traditional/public/2025-09/plateforme_numerique.webp?h=032abc86&itok=VwkW4LbB', 'https://www.aps.dz/algerie/education-et-technologie/mjyerd3t-%D8%AA%D9%88%D8%AC%D9%87-%D8%A8%D8%AE%D8%B7%D9%89-%D8%AB%D8%A7%D8%A8%D8%AA%D8%A9-%D9%86%D8%AD%D9%88-%D8%AA%D8%AD%D9%88%D9%84-%D8%B1%D9%82%D9%85%D9%8A-%D8%B4%D8%A7%D9%85%D9%84-%D8%AA%D8%AC%D8%B3%D9%8A%D8%AF%D8%A7-%D9%84%D8%AA%D8%B9%D9%84%D9%8A%D9%85%D8%A7%D8%AA-%D8%B1%D9%8A%D9%94%D9%8A%D8%B3-%D8%A7%D9%84%D8%AC%D9%85%D9%87%D9%88%D8%B1%D9%8A%D8%A9', 1, 7, '2026-02-06 09:54:55', '2026-02-06 09:54:55'),
(16, 'L’intelligence artificielle et la transformation digitale', 'fr', '\nLa transformation digitale en Algérie s''accélère, portée par des initiatives publiques, une jeunesse dynamique et une volonté affirmée d''intégrer les technologies de l’intelligence artificielle (IA) dans les secteurs clés de l’économie et de la société. Malgré les défis, le pays dispose d’atouts considérables pour réussir sa transition numérique : capital humain, stratégie nationale, écosystème entrepreneurial émergent. L’ère numérique transforme profondément les sociétés contemporaines, ouvrant la voie à de nouvelles formes d’organisation économique, sociale et politique.', 'https://elraed.dz/media/articles/67170-140825.jpg', 'https://www.elmoudjahid.dz/fr/actualite/l-intelligence-artificielle-et-la-transformation-digitale-quand-l-algerie-code-son-avenir-236042', 1, 8, '2026-02-06 10:02:49', '2026-02-06 10:02:49'),
(17, 'الذكاء الاصطناعي والتحول الرقمي', 'ar', 'الذكاء الاصطناعي يغيّر خريطة الوظائف والمهارات المطلوبة في سوق العمل في الجزائر\nوظائف تقليدية في طريقها للزوال مقابل صعود للمهن الرقمية ومهن المستقبل', 'https://elraed.dz/media/articles/67170-140825.jpg', 'https://elraed.dz/159048-%D8%A7%D9%84%D8%B0%D9%83%D8%A7--%D8%A7%D9%84%D8%A7%D8%B5%D8%B7%D9%86%D8%A7%D8%B9%D9%8A-%D9%8A%D8%BA%D9%8A-%D8%B1-%D8%AE%D8%B1%D9%8A%D8%B7%D8%A9-%D8%A7%D9%84%D9%88%D8%B8%D8%A7%D8%A6%D9%81-%D9%88%D8%A7%D9%84%D9%85%D9%87%D8%A7%D8%B1%D8%A7%D8%AA-%D8%A7%D9%84%D9%85%D8%B7%D9%84%D9%88%D8%A8%D8%A9-%D9%81%D9%8A-%D8%B3%D9%88%D9%82-%D8%A7%D9%84%D8%B9%D9%85%D9%84-%D9%81%D9%8A-%D8%A7%D9%84%D8%AC%D8%B2%D8%A7%D8%A6%D8%B1', 1, 8, '2026-02-06 10:05:19', '2026-02-06 10:05:19'),
(18, 'l''IA et l''enseignement supérieur', 'fr', 'Dans une déclaration à la presse en marge de sa conférence sur '' les leçons d’un parcours scientifique '', le chercheur a affirmé '' avoir relevé, au cours de sa rencontre avec le président de la République, M. Abdelmadjid Tebboune, une forte volonté d’assurer aux étudiants universitaires une formation de haut niveau qui réalise au pays le progrès voulu '', estimant que '' le recours à l’intelligence artificielle permet d’opérer un changement global au sein des universités du pays ''.', 'https://www.aps.dz/fr/_next/image?url=%2Ffr%2Fapi%2Fimage%2Farticle%2F0778540149d0a29a6eeccd2e1670aea3.jpeg&w=1080&q=75', 'https://www.aps.dz/fr/algerie/education-et-technologie/mjbsl3mt-necessaire-integration-de-l-ia-aux-efforts-de-developpement-de-l-enseignement-superieur', 1, 9, '2026-02-06 10:15:02', '2026-02-06 10:15:59'),
(19, 'الذكاء الاصطناعي والتعليم العالي', 'ar', 'سلط البروفيسور و الباحث الجزائري, إلياس زرهوني, اليوم الخميس من جامعة محمد خيضر ببسكرة, الضوء على "ضرورة توظيف الذكاء الاصطناعي في مساعي تطوير التعليم العالي لأجل تحقيق تطور شامل للبلاد".\n\nو أوضح ذات البروفيسور في تصريح للصحافة على هامش تقديمه محاضرة بعنوان "دروس من مسيرة علمية", بأنه "لمس من خلال لقائه مع رئيس الجمهورية, السيد عبد المجيد تبون, مؤخرا, إرادة قوية في مسعى تمكين الطلبة الجامعيين من مستوى تكويني عالي يحقق للبلاد التطور المنشود", مفيدا بأن "استخدام الذكاء الاصطناعي يمكن من تغيير شامل على مستوى جامعات الوطن".', 'https://www.aps.dz/fr/_next/image?url=%2Ffr%2Fapi%2Fimage%2Farticle%2F0778540149d0a29a6eeccd2e1670aea3.jpeg&w=1080&q=75', 'https://www.aps.dz/algerie/education-et-technologie/mjbu5mwc-%D8%B6%D8%B1%D9%88%D8%B1%D8%A9-%D8%AA%D9%88%D8%B8%D9%8A%D9%81-%D8%A7%D9%84%D8%B0%D9%83%D8%A7%D8%A1-%D8%A7%D9%84%D8%B0%D9%83%D8%A7%D8%A1-%D8%A7%D9%84%D8%A7%D8%B5%D8%B7%D9%86%D8%A7%D8%B9%D9%8A-%D9%81%D9%8A-%D9%85%D8%B3%D8%A7%D8%B9%D9%8A-%D8%AA%D8%B7%D9%88%D9%8A%D8%B1-%D8%A7%D9%84%D8%AA%D8%B9%D9%84%D9%8A%D9%85-%D8%A7%D9%84%D8%B9%D8%A7%D9%84%D9%8A', 1, 9, '2026-02-06 10:17:56', '2026-02-06 10:17:56');
